class Solution:
    def minSumSquareDiff(self, nums1, nums2, k1, k2):
        import heapq
        diffs = [abs(a - b) for a, b in zip(nums1, nums2)]
        budget = k1 + k2
        if budget >= sum(diffs):
            return 0
        # max-heap, spend one unit at a time on the largest gap
        heap = [-d for d in diffs if d > 0]
        heapq.heapify(heap)
        while budget > 0 and heap:
            top = -heap[0]
            if top == 0:
                break
            # reduce the largest by one
            heapq.heapreplace(heap, -(top - 1))
            budget -= 1
        return sum(v * v for v in (-x for x in heap))

