class Solution:
    def minSumSquareDiff(self, nums1, nums2, k1, k2):
        diffs = [abs(a - b) for a, b in zip(nums1, nums2)]
        budget = k1 + k2
        if budget >= sum(diffs):
            return 0
        n = len(diffs)
        # find level L such that we can bring every gap down to <= L
        # cost to bring all gaps down to level x is sum(max(0, d - x))
        lo, hi = 0, max(diffs)
        def cost(x):
            return sum(d - x for d in diffs if d > x)
        while lo < hi:
            mid = (lo + hi) // 2
            if cost(mid) <= budget:
                hi = mid
            else:
                lo = mid + 1
        level = lo
        # after flattening to 'level', leftover units push some gaps to level-1
        remaining = budget - cost(level)
        cnt_at_level = sum(1 for d in diffs if d > level)
        # actually gaps strictly greater than level are now exactly 'level'; those equal to level stay
        # number of gaps currently sitting at 'level' (and were >= level originally)
        at_level = sum(1 for d in diffs if d >= level) if level > 0 else 0
        total = 0
        # build final gaps
        finals = []
        for d in diffs:
            finals.append(min(d, level))
        # spend remaining units lowering gaps that equal 'level' to level-1
        idx = 0
        finals.sort(reverse=True)
        i = 0
        while remaining > 0 and i < len(finals) and finals[i] > 0:
            if finals[i] == level:
                finals[i] -= 1
                remaining -= 1
                i += 1
            else:
                break
        return sum(v * v for v in finals)

