var minSumSquareDiff = function(nums1, nums2, k1, k2) {
    const diffs = nums1.map((a, i) => Math.abs(a - nums2[i]));
    let budget = k1 + k2;
    let totalGap = 0;
    for (const d of diffs) totalGap += d;
    if (budget >= totalGap) return 0;
    const maxd = Math.max(...diffs);
    const cost = (x) => {
        let c = 0;
        for (const d of diffs) if (d > x) c += d - x;
        return c;
    };
    let lo = 0, hi = maxd;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (cost(mid) <= budget) hi = mid; else lo = mid + 1;
    }
    const level = lo;
    let remaining = budget - cost(level);
    const finals = diffs.map(d => Math.min(d, level));
    finals.sort((a, b) => b - a);
    let i = 0;
    while (remaining > 0 && i < finals.length && finals[i] > 0) {
        if (finals[i] === level) {
            finals[i] -= 1;
            remaining -= 1;
            i += 1;
        } else {
            break;
        }
    }
    let res = 0n;
    for (const v of finals) res += BigInt(v) * BigInt(v);
    return Number(res);
};
